/* ============================================================
 * AI GO 起手式模板 — App.css
 * 精簡設計系統：:host / :root 變數 ＋ 暗色模式 ＋ 手寫 utility
 * 主色系：Indigo (#4f46e5)  ·  字型：Inter (Google Fonts)
 * ============================================================ */

/* ── 字型引入 ── */
@import url("https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap");

/* ==========================================================
 *  1. 主題變數（亮色）
 * ========================================================== */
:host,
:root {
  /* 主色 */
  --primary: #4f46e5;
  --primary-hover: #4338ca;
  --primary-foreground: #ffffff;

  /* 語意色 */
  --success: #16a34a;
  --success-light: #dcfce7;
  --warning: #f59e0b;
  --warning-light: #fef3c7;
  --destructive: #ef4444;
  --destructive-light: #fee2e2;

  /* 中性色 */
  --background: #f8fafc;
  --foreground: #0f172a;
  --card: #ffffff;
  --card-foreground: #0f172a;
  --muted: #f1f5f9;
  --muted-foreground: #64748b;
  --text-secondary: #64748b;
  --border: #e2e8f0;

  /* 圓角 / 字型 */
  --radius: 0.5rem;
  --font-sans: "Inter", ui-sans-serif, system-ui, -apple-system, sans-serif;

  /* 側欄寬度 */
  --sidebar-width: 240px;
  --sidebar-collapsed-width: 0px;
  --header-height: 56px;
}

/* ==========================================================
 *  2. 暗色模式
 * ========================================================== */
[data-theme="dark"],
:host([data-theme="dark"]) {
  --primary: #818cf8;
  --primary-hover: #6366f1;
  --primary-foreground: #0f172a;

  --success: #4ade80;
  --success-light: #14532d;
  --warning: #fbbf24;
  --warning-light: #422006;
  --destructive: #f87171;
  --destructive-light: #450a0a;

  --background: #0f172a;
  --foreground: #f1f5f9;
  --card: #1e293b;
  --card-foreground: #f1f5f9;
  --muted: #1e293b;
  --muted-foreground: #94a3b8;
  --text-secondary: #94a3b8;
  --border: #334155;
}

/* ==========================================================
 *  3. Reset / Base
 * ========================================================== */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  font-size: 16px;
  -webkit-text-size-adjust: 100%;
}

body {
  font-family: var(--font-sans);
  background: var(--background);
  color: var(--foreground);
  line-height: 1.6;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

a {
  color: var(--primary);
  text-decoration: none;
}

img {
  max-width: 100%;
  display: block;
}

/* ==========================================================
 *  4. App 佈局
 * ========================================================== */
.app-layout {
  display: flex;
  min-height: 100vh;
}

.app-main {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-width: 0; /* 防止 flex 子項目溢出 */
}

.app-content {
  flex: 1;
  padding: 1.5rem;
  overflow-y: auto;
}

/* ==========================================================
 *  5. 側邊欄
 * ========================================================== */
.app-sidebar {
  width: var(--sidebar-width);
  background: var(--card);
  border-right: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  transition: width 0.2s ease, opacity 0.2s ease;
  overflow: hidden;
  flex-shrink: 0;
}

.app-sidebar.collapsed {
  width: var(--sidebar-collapsed-width);
  opacity: 0;
  pointer-events: none;
}

/* ── 品牌標識 ── */
.sidebar-brand {
  height: var(--header-height);
  display: flex;
  align-items: center;
  padding: 0 1rem;
  font-weight: 700;
  font-size: 1.05rem;
  border-bottom: 1px solid var(--border);
  white-space: nowrap;
}

/* ── 導覽區 ── */
.sidebar-nav {
  flex: 1;
  padding: 0.5rem;
  overflow-y: auto;
}

.sidebar-item {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  width: 100%;
  padding: 0.5rem 0.75rem;
  border: none;
  background: none;
  color: var(--muted-foreground);
  font-size: 0.875rem;
  font-family: inherit;
  border-radius: var(--radius);
  cursor: pointer;
  transition: background 0.15s, color 0.15s;
  white-space: nowrap;
}

.sidebar-item:hover {
  background: var(--muted);
  color: var(--foreground);
}

.sidebar-item.active {
  background: var(--primary);
  color: var(--primary-foreground);
}

/* ── 展開箭頭 ── */
.sidebar-chevron {
  margin-left: auto;
  transition: transform 0.2s;
}

.sidebar-chevron.open {
  transform: rotate(180deg);
}

/* ==========================================================
 *  6. 頂部列
 * ========================================================== */
.app-header {
  height: var(--header-height);
  display: flex;
  align-items: center;
  padding: 0 1.5rem;
  background: var(--card);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}

.header-left {
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.header-menu-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 2rem;
  height: 2rem;
  border: none;
  background: none;
  color: var(--foreground);
  border-radius: var(--radius);
  cursor: pointer;
  transition: background 0.15s;
}

.header-menu-btn:hover {
  background: var(--muted);
}

.header-title {
  font-size: 1rem;
  font-weight: 600;
}

.header-right {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  margin-left: auto;
}

.header-user {
  font-size: 0.8125rem;
  color: var(--muted-foreground);
}

/* ==========================================================
 *  7. 頁面容器
 * ========================================================== */
.page-container {
  max-width: 1200px;
  margin: 0 auto;
  width: 100%;
}

.page-header {
  margin-bottom: 1.5rem;
}

.page-title {
  font-size: 1.5rem;
  font-weight: 700;
  line-height: 1.3;
}

.page-description {
  color: var(--muted-foreground);
  font-size: 0.875rem;
  margin-top: 0.25rem;
}

/* ==========================================================
 *  8. 卡片
 * ========================================================== */
.card {
  background: var(--card);
  color: var(--card-foreground);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  overflow: hidden;
}

.card-header {
  padding: 1rem 1.25rem;
}

.card-title {
  font-size: 1rem;
  font-weight: 600;
  line-height: 1.4;
}

.card-description {
  color: var(--muted-foreground);
  font-size: 0.8125rem;
  margin-top: 0.125rem;
}

.card-content {
  padding: 0 1.25rem 1.25rem;
}

/* ==========================================================
 *  9. 表格
 * ========================================================== */
.table-wrapper {
  overflow-x: auto;
}

.table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.875rem;
}

.table thead {
  border-bottom: 1px solid var(--border);
}

.table th {
  text-align: left;
  padding: 0.625rem 1rem;
  font-weight: 500;
  color: var(--muted-foreground);
  font-size: 0.8125rem;
  white-space: nowrap;
}

.table td {
  padding: 0.625rem 1rem;
  border-bottom: 1px solid var(--border);
  vertical-align: middle;
}

.table tbody tr:hover {
  background: var(--muted);
}

.table tbody tr:last-child td {
  border-bottom: none;
}

/* ==========================================================
 *  10. 表單
 * ========================================================== */
.form-group {
  margin-bottom: 0.75rem;
}

.form-group label {
  display: block;
  font-size: 0.8125rem;
  font-weight: 500;
  margin-bottom: 0.25rem;
  color: var(--foreground);
}

.form-group input,
.form-group select,
.form-group textarea {
  width: 100%;
  padding: 0.5rem 0.75rem;
  font-size: 0.875rem;
  font-family: inherit;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  background: var(--background);
  color: var(--foreground);
  outline: none;
  transition: border-color 0.15s, box-shadow 0.15s;
}

.form-group input:focus,
.form-group select:focus,
.form-group textarea:focus {
  border-color: var(--primary);
  box-shadow: 0 0 0 3px rgba(79, 70, 229, 0.15);
}

.form-group input::placeholder {
  color: var(--muted-foreground);
}

/* ==========================================================
 *  11. 按鈕
 * ========================================================== */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.375rem;
  padding: 0.5rem 1rem;
  font-size: 0.875rem;
  font-weight: 500;
  font-family: inherit;
  border: 1px solid transparent;
  border-radius: var(--radius);
  cursor: pointer;
  transition: background 0.15s, color 0.15s, border-color 0.15s, opacity 0.15s;
  white-space: nowrap;
  line-height: 1.4;
}

.btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

/* 主色按鈕 */
.btn-primary {
  background: var(--primary);
  color: var(--primary-foreground);
}

.btn-primary:hover:not(:disabled) {
  background: var(--primary-hover);
}

/* 外框按鈕 */
.btn-outline {
  background: transparent;
  color: var(--foreground);
  border-color: var(--border);
}

.btn-outline:hover:not(:disabled) {
  background: var(--muted);
}

/* 幽靈按鈕 */
/* 幽靈按鈕 */
.btn-ghost {
  background: transparent;
  color: var(--muted-foreground);
}

.btn-ghost:hover:not(:disabled) {
  background: var(--muted);
  color: var(--foreground);
}

/* 連結按鈕 */
.btn-link {
  background: transparent;
  color: var(--primary);
  border: none;
  padding: 0;
  font-weight: 500;
  text-decoration: underline;
  display: inline;
  height: auto;
}

.btn-link:hover:not(:disabled) {
  color: var(--primary-hover);
  text-decoration: none;
}

/* 小尺寸 */
.btn-sm {
  padding: 0.25rem 0.5rem;
  font-size: 0.8125rem;
}

/* 全寬 */
.w-full {
  width: 100%;
}

/* ==========================================================
 *  12. 徽章
 * ========================================================== */
.badge {
  display: inline-flex;
  align-items: center;
  padding: 0.125rem 0.5rem;
  font-size: 0.75rem;
  font-weight: 500;
  border-radius: 9999px;
  white-space: nowrap;
  line-height: 1.6;
}

.badge-primary {
  background: rgba(79, 70, 229, 0.12);
  color: var(--primary);
}

.badge-success {
  background: var(--success-light);
  color: var(--success);
}

.badge-warning {
  background: var(--warning-light);
  color: var(--warning);
}

.badge-outline {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--foreground);
}

.badge-default {
  background: var(--muted);
  color: var(--muted-foreground);
}

/* ==========================================================
 *  13. 對話框 (Dialog)
 * ========================================================== */
.dialog-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  padding: 1rem;
}

.dialog-content {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  width: 100%;
  max-width: 480px;
  padding: 1.5rem;
  position: relative;
  max-height: 90vh;
  overflow-y: auto;
  animation: dialog-in 0.15s ease;
}

@keyframes dialog-in {
  from {
    opacity: 0;
    transform: scale(0.96) translateY(8px);
  }
  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

.dialog-close {
  position: absolute;
  top: 0.75rem;
  right: 0.75rem;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 1.75rem;
  height: 1.75rem;
  border: none;
  background: none;
  color: var(--muted-foreground);
  border-radius: var(--radius);
  cursor: pointer;
}

.dialog-close:hover {
  background: var(--muted);
  color: var(--foreground);
}

.dialog-header {
  margin-bottom: 1rem;
}

.dialog-title {
  font-size: 1.125rem;
  font-weight: 600;
}

.dialog-description {
  color: var(--muted-foreground);
  font-size: 0.8125rem;
  margin-top: 0.25rem;
}

.dialog-footer {
  display: flex;
  justify-content: flex-end;
  gap: 0.5rem;
  margin-top: 1rem;
  padding-top: 1rem;
  border-top: 1px solid var(--border);
}

/* ==========================================================
 *  14. 統計指標
 * ========================================================== */
.stat-label {
  font-size: 0.8125rem;
  color: var(--muted-foreground);
  font-weight: 500;
}

.stat-value {
  font-size: 1.75rem;
  font-weight: 700;
  line-height: 1.2;
  margin-top: 0.25rem;
  display: block;
}

/* ==========================================================
 *  15. 空狀態
 * ========================================================== */
.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 3rem 1rem;
  text-align: center;
  color: var(--muted-foreground);
}

.empty-icon {
  font-size: 2.5rem;
  margin-bottom: 0.75rem;
}

/* ==========================================================
 *  16. 搜尋列
 * ========================================================== */
.search-bar {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 0 0.75rem;
  background: var(--background);
  transition: border-color 0.15s;
}

.search-bar:focus-within {
  border-color: var(--primary);
  box-shadow: 0 0 0 3px rgba(79, 70, 229, 0.15);
}

.search-bar svg {
  flex-shrink: 0;
  color: var(--muted-foreground);
}

.search-bar input {
  flex: 1;
  border: none;
  background: none;
  padding: 0.5rem 0;
  font-size: 0.875rem;
  font-family: inherit;
  color: var(--foreground);
  outline: none;
}

.search-bar input::placeholder {
  color: var(--muted-foreground);
}

/* ==========================================================
 *  17. 登入 / Auth（外部應用共用）
 * ========================================================== */
.auth-container {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  padding: 1rem;
  background: var(--background);
}

.auth-card {
  width: 100%;
  max-width: 400px;
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 2rem;
}

.auth-header {
  text-align: center;
  margin-bottom: 1.5rem;
}

.auth-header h1 {
  font-size: 1.25rem;
  font-weight: 700;
}

.auth-header p {
  color: var(--muted-foreground);
  font-size: 0.875rem;
  margin-top: 0.25rem;
}

.auth-tabs {
  display: flex;
  border-bottom: 1px solid var(--border);
  margin-bottom: 1.25rem;
}

.auth-tab {
