import React, { useState, useCallback, useEffect } from "react";
import { HashRouter, Routes, Route } from "react-router-dom";
import { Toaster } from "react-hot-toast";
import AppLayout from "./components/AppLayout";
import DashboardPage from "./pages/DashboardPage";
import ListPage from "./pages/ListPage";
import NotFoundPage from "./pages/NotFoundPage";
import LoginPage from "./pages/LoginPage";
import { logout, getCurrentUser } from "./auth";

/**
 * 取得 localStorage 中的 token storage key
 * 與 auth.ts 保持一致的 key 命名規則
 */
function getStorageKey(): string {
  const slug = (window as any).__APP_SLUG__ || "";
  return `custom_app_auth_${slug}`;
}

/**
 * 檢查是否已登入（localStorage 中是否存在 token）
 */
function checkAuth(): boolean {
  const stored = localStorage.getItem(getStorageKey());
  if (!stored) return false;
  try {
    const tokens = JSON.parse(stored);
    return !!(tokens.access_token || tokens.token);
  } catch {
    return false;
  }
}

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(checkAuth());
  const [userName, setUserName] = useState<string>("");

  /** 登入成功後的回呼：更新驗證狀態 */
  const handleLoginSuccess = useCallback(() => {
    setIsAuthenticated(true);
  }, []);

  /** 登出回呼：清除 token 並回到登入頁 */
  const handleLogout = useCallback(async () => {
    await logout();
    (window as any).__APP_TOKEN__ = "";
    (window as any).__CURRENT_USER__ = null;
    setIsAuthenticated(false);
    setUserName("");
  }, []);

  /** 登入後取得使用者資訊 */
  useEffect(() => {
    if (!isAuthenticated) return;

    /* 先嘗試從 localStorage 還原 token 到 window */
    const stored = localStorage.getItem(getStorageKey());
    if (stored) {
      try {
        const tokens = JSON.parse(stored);
        (window as any).__APP_TOKEN__ = tokens.access_token || tokens.token || "";
      } catch { /* 忽略解析錯誤 */ }
    }

    /* 取得當前使用者名稱 */
    getCurrentUser()
      .then((user) => {
        (window as any).__CURRENT_USER__ = user;
        if (user?.display_name) {
          setUserName(user.display_name);
        } else if (user?.email) {
          setUserName(user.email);
        }
      })
      .catch(() => { /* 靜默處理 */ });
  }, [isAuthenticated]);

  /* ── 未登入：顯示登入頁 ── */
  if (!isAuthenticated) {
    return (
      <>
        <Toaster position="top-right" />
        <LoginPage onLoginSuccess={handleLoginSuccess} />
      </>
    );
  }

  /* ── 已登入：顯示主應用 ── */
  return (
    <>
      <Toaster position="top-right" />
      <HashRouter>
        <AppLayout
          appName={"opttwo官網"}
          onLogout={handleLogout}
          userName={userName}
        >
          <Routes>
            <Route path="/" element={<DashboardPage />} />
            <Route path="/leads" element={<ListPage />} />
            <Route path="*" element={<NotFoundPage />} />
          </Routes>
        </AppLayout>
      </HashRouter>
    </>
  );
}

