import React, { useState, useEffect } from "react";
import { Search, Plus, X, BarChart3, Loader2, Pencil } from "lucide-react";
import { listRecords, submitRecord, updateRecord, deleteRecord } from "../api";
import * as db from "../db";
import { runAction } from "../action";
import dataJson from "../data.json";

export const pageTitle = "潛在客戶";

import toast from "react-hot-toast";

// data.json 格式：{ "表名": { id, slug, fields, records }, ... } 或 []
function findLeadsTable(data: any): any {
  if (!data || typeof data !== "object") return null;
  const entries = Array.isArray(data) ? data : Object.values(data);
  return entries.find((t: any) => t?.slug?.startsWith("leads")) || null;
}

const emptyForm = { name: "", email: "", phone: "", company: "", source: "", status: "新線索" };

export default function ListPage() {
  const [records, setRecords] = useState<any[]>([]);
  const [tags, setTags] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [showCreateDialog, setShowCreateDialog] = useState(false);
  const [showEditDialog, setShowEditDialog] = useState(false);
  const [editingRecord, setEditingRecord] = useState<any>(null);
  const [formData, setFormData] = useState({ ...emptyForm });
  const [summarizing, setSummarizing] = useState(false);
  const [summary, setSummary] = useState<any>(null);
  const [tableId, setTableId] = useState("");

  // 從 data.json 取得 leads table ID
  useEffect(() => {
    const leadsTable = findLeadsTable(dataJson);
    if (leadsTable?.id) {
      setTableId(leadsTable.id);
    }
  }, []);

  // 載入資料
  useEffect(() => {
    if (tableId) {
      loadData();
    } else {
      setLoading(false);
    }
    loadTags();
  }, [tableId]);

  const loadData = async () => {
    setLoading(true);
    try {
      const data = await listRecords(tableId);
      setRecords(Array.isArray(data) ? data : []);
    } catch (_) {}
    setLoading(false);
  };

  const loadTags = async () => {
    try {
      const rows = await db.query("crm_tags", { limit: 100 });
      setTags(Array.isArray(rows) ? rows : []);
    } catch (_) {}
  };

  const handleCreate = async () => {
    if (!formData.name.trim() || !tableId) return;
    try {
      await submitRecord(tableId, formData);
      toast.success("新增成功");
      setShowCreateDialog(false);
      setFormData({ ...emptyForm });
      await loadData();
    } catch (e: any) {
      toast.error(e.message || "新增失敗");
      console.error("新增失敗", e);
    }
  };

  // ── 編輯 ──
  const openEdit = (record: any) => {
    const d = record?.data || record || {};
    setEditingRecord(record);
    setFormData({
      name: d.name || "",
      email: d.email || "",
      phone: d.phone || "",
      company: d.company || "",
      source: d.source || "",
      status: d.status || "新線索",
    });
    setShowEditDialog(true);
  };

  const handleUpdate = async () => {
    if (!editingRecord || !tableId) return;
    const recordId = editingRecord.id || editingRecord._id;
    try {
      await updateRecord(tableId, recordId, formData);
      toast.success("更新成功");
      setShowEditDialog(false);
      setEditingRecord(null);
      setFormData({ ...emptyForm });
      await loadData();
    } catch (e: any) {
      toast.error(e.message || "更新失敗");
      console.error("更新失敗", e);
    }
  };

  // ── 刪除 ──
  const handleDelete = async (recordId: string) => {
    if (!tableId) return;
    try {
      await deleteRecord(tableId, recordId);
      toast.success("刪除成功");
      await loadData();
    } catch (e: any) {
      toast.error(e.message || "刪除失敗");
      console.error("刪除失敗", e);
    }
  };

  // ── 資料摘要（示範前後端 Action 協作）──
  const handleSummary = async () => {
    setSummarizing(true);
    setSummary(null);
    try {
      const result = await runAction("summarize_leads", { records });
      const data = result?.data?.result || result?.result || result?.data || result;
      setSummary(data);
      toast.success("摘要完成");
    } catch (e: any) {
      toast.error(e.message || "摘要失敗");
      console.error("摘要失敗", e);
    }
    setSummarizing(false);
  };

  const filtered = records.filter((r) => {
    const data = r?.data || r || {};
    const q = search.toLowerCase();
    return (data.name || "").toLowerCase().includes(q) || (data.email || "").toLowerCase().includes(q);
  });

  // ── 表單 Dialog（新增/編輯共用） ──
  const renderFormDialog = (opts: { title: string; desc: string; onSubmit: () => void; submitLabel: string; open: boolean; onClose: () => void }) => {
    if (!opts.open) return null;
    return (
      <div className="dialog-overlay" onClick={opts.onClose}>
        <div className="dialog-content" onClick={(e) => e.stopPropagation()}>
          <button className="dialog-close" onClick={opts.onClose}><X size={16} /></button>
          <div className="dialog-header">
            <h2 className="dialog-title">{opts.title}</h2>
            <p className="dialog-description">{opts.desc}</p>
          </div>
          <div className="form-group">
            <label>客戶名稱 *</label>
            <input placeholder="請輸入名稱" value={formData.name} onChange={(e) => setFormData({ ...formData, name: e.target.value })} />
          </div>
          <div className="grid grid-2 gap-4">
            <div className="form-group">
              <label>Email</label>
              <input type="email" placeholder="email@example.com" value={formData.email} onChange={(e) => setFormData({ ...formData, email: e.target.value })} />
            </div>
            <div className="form-group">
              <label>電話</label>
              <input placeholder="0912-345-678" value={formData.phone} onChange={(e) => setFormData({ ...formData, phone: e.target.value })} />
            </div>
          </div>
          <div className="grid grid-2 gap-4">
            <div className="form-group">
              <label>公司名稱</label>
              <input placeholder="公司名稱" value={formData.company} onChange={(e) => setFormData({ ...formData, company: e.target.value })} />
            </div>
            <div className="form-group">
              <label>來源</label>
              <select value={formData.source} onChange={(e) => setFormData({ ...formData, source: e.target.value })}>
                <option value="">請選擇</option>
                <option value="官網">官網</option>
                <option value="廣告">廣告</option>
                <option value="推薦">推薦</option>
                <option value="展覽">展覽</option>
                <option value="其他">其他</option>
              </select>
            </div>
          </div>
          <div className="form-group">
            <label>狀態</label>
            <select value={formData.status} onChange={(e) => setFormData({ ...formData, status: e.target.value })}>
              <option value="新線索">新線索</option>
              <option value="跟進中">跟進中</option>
              <option value="已轉換">已轉換</option>
              <option value="已關閉">已關閉</option>
            </select>
          </div>
          <div className="dialog-footer">
            <button className="btn btn-outline" onClick={opts.onClose}>取消</button>
            <button className="btn btn-primary" onClick={opts.onSubmit} disabled={!formData.name.trim()}>{opts.submitLabel}</button>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="page-container">
      <div className="flex items-center justify-between mb-6">
        <div className="page-header mb-0">
