import React, { useState, FormEvent } from "react";

/**
 * LoginPage — 外部應用的登入/註冊頁面
 *
 * 功能：
 * - Tab 切換「登入」/「註冊」
 * - 登入：POST /api/v1/custom-app-auth/{slug}/login
 * - 註冊：POST /api/v1/custom-app-auth/{slug}/register
 * - 成功後將 token 存入 localStorage 並設定 window.__APP_TOKEN__
 */

/** API 基底路徑，與 auth.ts 保持一致 */
const API_BASE = (window as any).__API_BASE__ || "/api/v1";

/** 取得應用 slug */
function getSlug(): string {
  return (window as any).__APP_SLUG__ || "";
}

/** 組合 API 請求標頭 */
function _getHeaders(): Record<string, string> {
  return { "Content-Type": "application/json" };
}

/** 登入/註冊的 Tab 類型 */
type AuthTab = "login" | "register";

interface LoginPageProps {
  /** 登入成功後的回呼 */
  onLoginSuccess: () => void;
}

export default function LoginPage({ onLoginSuccess }: LoginPageProps) {
  const [activeTab, setActiveTab] = useState<AuthTab>("login");

  /* ── 共用欄位 ── */
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  /* ── 註冊專用欄位 ── */
  const [displayName, setDisplayName] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");

  /* ── 狀態 ── */
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);

  /** 切換 Tab 時清除所有狀態 */
  const switchTab = (tab: AuthTab) => {
    setActiveTab(tab);
    setError("");
    setSuccess("");
    setEmail("");
    setPassword("");
    setDisplayName("");
    setConfirmPassword("");
  };

  /** 處理登入 */
  const handleLogin = async (e: FormEvent) => {
    e.preventDefault();
    setError("");
    setSuccess("");

    if (!email || !password) {
      setError("請填寫 Email 與密碼");
      return;
    }

    setLoading(true);
    try {
      const slug = getSlug();
      const resp = await fetch(
        `${API_BASE}/custom-app-auth/${slug}/login`,
        {
          method: "POST",
          headers: _getHeaders(),
          body: JSON.stringify({ email, password }),
        }
      );

      if (!resp.ok) {
        const data = await resp.json().catch(() => null);
        throw new Error(data?.detail || data?.message || "登入失敗，請檢查帳號密碼");
      }

      const tokens = await resp.json();
      const storageKey = `custom_app_auth_${slug}`;

      /* 將 token 存入 localStorage */
      localStorage.setItem(storageKey, JSON.stringify(tokens));

      /* 設定全域 token 供 auth.ts SDK 使用 */
      (window as any).__APP_TOKEN__ = tokens.access_token || tokens.token || "";

      onLoginSuccess();
    } catch (err: any) {
      setError(err.message || "登入時發生未知錯誤");
    } finally {
      setLoading(false);
    }
  };

  /** 處理註冊 */
  const handleRegister = async (e: FormEvent) => {
    e.preventDefault();
    setError("");
    setSuccess("");

    /* 前端驗證 */
    if (!displayName || !email || !password || !confirmPassword) {
      setError("請填寫所有欄位");
      return;
    }
    if (password !== confirmPassword) {
      setError("兩次輸入的密碼不一致");
      return;
    }
    if (password.length < 6) {
      setError("密碼長度至少需要 6 個字元");
      return;
    }

    setLoading(true);
    try {
      const slug = getSlug();
      const resp = await fetch(
        `${API_BASE}/custom-app-auth/${slug}/register`,
        {
          method: "POST",
          headers: _getHeaders(),
          body: JSON.stringify({
            email,
            password,
            display_name: displayName,
          }),
        }
      );

      if (!resp.ok) {
        const data = await resp.json().catch(() => null);
        throw new Error(data?.detail || data?.message || "註冊失敗，請稍後再試");
      }

      setSuccess("註冊成功！請切換至登入頁面進行登入。");
      /* 清除表單 */
      setDisplayName("");
      setEmail("");
      setPassword("");
      setConfirmPassword("");
    } catch (err: any) {
      setError(err.message || "註冊時發生未知錯誤");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-container">
      <div className="auth-card">
        {/* ── 標題 ── */}
        <div className="auth-header">
          <h1>{"{{APP_NAME}}"}</h1>
          <p>歡迎使用，請登入或註冊帳號</p>
        </div>

        {/* ── Tab 切換 ── */}
        <div className="auth-tabs">
          <button
            className={`auth-tab ${activeTab === "login" ? "active" : ""}`}
            onClick={() => switchTab("login")}
            type="button"
          >
            登入
          </button>
          <button
            className={`auth-tab ${activeTab === "register" ? "active" : ""}`}
            onClick={() => switchTab("register")}
            type="button"
          >
            註冊
          </button>
        </div>

        {/* ── 錯誤訊息 ── */}
        {error && <div className="auth-error">{error}</div>}

        {/* ── 成功訊息 ── */}
        {success && <div className="auth-success">{success}</div>}

        {/* ── 登入表單 ── */}
        {activeTab === "login" && (
          <form className="auth-form" onSubmit={handleLogin}>
            <div className="form-group">
              <label htmlFor="login-email">Email</label>
              <input
                id="login-email"
                type="email"
                placeholder="請輸入 Email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                autoComplete="email"
              />
            </div>
            <div className="form-group">
              <label htmlFor="login-password">密碼</label>
              <input
                id="login-password"
                type="password"
                placeholder="請輸入密碼"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                autoComplete="current-password"
              />
            </div>
            <button
              type="submit"
              className="btn btn-primary w-full"
              disabled={loading}
            >
              {loading ? "登入中…" : "登入"}
            </button>
          </form>
        )}

        {/* ── 註冊表單 ── */}
        {activeTab === "register" && (
          <form className="auth-form" onSubmit={handleRegister}>
            <div className="form-group">
              <label htmlFor="reg-name">顯示名稱</label>
              <input
                id="reg-name"
                type="text"
                placeholder="請輸入顯示名稱"
                value={displayName}
                onChange={(e) => setDisplayName(e.target.value)}
                autoComplete="name"
              />
            </div>
            <div className="form-group">
              <label htmlFor="reg-email">Email</label>
              <input
                id="reg-email"
                type="email"
                placeholder="請輸入 Email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                autoComplete="email"
              />
            </div>
            <div className="form-group">
              <label htmlFor="reg-password">密碼</label>
              <input
                id="reg-password"
                type="password"
                placeholder="請輸入密碼（至少 6 字元）"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                autoComplete="new-password"
              />
            </div>
            <div className="form-group">
              <label htmlFor="reg-confirm">確認密碼</label>
              <input
                id="reg-confirm"
                type="password"
                placeholder="請再次輸入密碼"
                value={confirmPassword}
                onChange={(e) => setConfirmPassword(e.target.value)}
                autoComplete="new-password"
              />
            </div>
            <button
              type="submit"
              className="btn btn-primary w-full"
              disabled={loading}
            >
              {loading ? "註冊中…" : "註冊"}
            </button>
          </form>
        )}

        {/* ── 頁腳 ── */}
        <div className="auth-footer">
          {activeTab === "login" ? (
            <p>
              還沒有帳號？{" "}
              <button
                type="button"
                className="btn btn-link"
                onClick={() => switchTab("register")}
              >
                立即註冊
              </button>
            </p>
          ) : (
            <p>
              已有帳號？{" "}
              <button
                type="button"
                className="btn btn-link"
                onClick={() => switchTab("login")}
              >
                前往登入
              </button>
            </p>
          )}
        </div>
      </div>
    </div>
  );
}

